messages.content:
{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Validate required fields, create patient record, and generate unique patient_id",
      "behavior": "Check that name, dob, contact, insurance are present and non-empty; generate a new patient_id; store patient data in patients database; return success with patient_id",
      "boundary": {
        "in_scope": [
          "field validation",
          "patient_id generation",
          "database write"
        ],
        "out_of_scope": [
          "appointment booking",
          "record retrieval",
          "profile update"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with name, dob, contact, insurance",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result with success flag, patient_id, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command is 'register'"
      ],
      "postconditions": [
        "patient record exists in patients database"
      ],
      "guarantees": [
        "patient_id is unique",
        "required fields are validated"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "BookAppointment",
      "purpose": "Check patient exists, check doctor availability, create appointment record, send confirmation",
      "behavior": "Verify patient_id exists in patients database; check that appointment_time is not in the past; check doctor availability (no conflicting appointments); create appointment record with status 'confirmed'; return success with appointment details",
      "boundary": {
        "in_scope": [
          "patient existence check",
          "time validation",
          "availability check",
          "appointment creation"
        ],
        "out_of_scope": [
          "patient registration",
          "record retrieval",
          "profile update"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with patient_id, doctor_id, appointment_time",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result with success flag, appointment_id, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command is 'book'",
        "patient is registered"
      ],
      "postconditions": [
        "appointment record exists in appointments database"
      ],
      "guarantees": [
        "appointment is not in the past",
        "doctor is available"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "RetrieveRecords",
      "purpose": "Retrieve all medical records for a patient, sorted by date descending",
      "behavior": "Look up patient_id in records database; collect all records for that patient; sort by timestamp descending; return list of records",
      "boundary": {
        "in_scope": [
          "record retrieval",
          "sorting"
        ],
        "out_of_scope": [
          "patient registration",
          "appointment booking",
          "profile update"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with patient_id",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result with success flag, list of records, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command is 'records'",
        "patient exists"
      ],
      "postconditions": [
        "records are returned sorted by date descending"
      ],
      "guarantees": [
        "records are append-only, not modified"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "UpdatePatientProfile",
      "purpose": "Update patient profile fields, validate insurance change against external system",
      "behavior": "Update provided fields in patients database; if insurance field is present, validate against external system before saving; return success with updated data",
      "boundary": {
        "in_scope": [
          "profile update",
          "insurance validation"
        ],
        "out_of_scope": [
          "patient registration",
          "appointment booking",
          "record retrieval"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with patient_id and fields to update",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result with success flag, updated data, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command is 'update'",
        "patient exists"
      ],
      "postconditions": [
        "patient profile is updated in database"
      ],
      "guarantees": [
        "insurance change is validated externally"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "Each child handles exactly one command, covering all four operations (register, book, records, update) without overlap. The parent routes based on command and passes patient_data directly.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "RegisterPatient",
      "data": "command='register', patient_data",
      "note": "route to register handler"
    },
    {
      "from": "parent",
      "to": "BookAppointment",
      "data": "command='book', patient_data",
      "note": "route to book handler"
    },
    {
      "from": "parent",
      "to": "RetrieveRecords",
      "data": "command='records', patient_data",
      "note": "route to records handler"
    },
    {
      "from": "parent",
      "to": "UpdatePatientProfile",
      "data": "command='update', patient_data",
      "note": "route to update handler"
    },
    {
      "from": "RegisterPatient",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    },
    {
      "from": "BookAppointment",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    },
    {
      "from": "RetrieveRecords",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    },
    {
      "from": "UpdatePatientProfile",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    }
  ]
}
